    "text": "\\rules only filteredtranscludeinline transcludeinline\n\n/* ── ahu section layout ─────────────────────────────────────────────────── */\n\n.tc-lararium-ahu-sections {\n  margin-top: 1em;\n  border-top: 1px solid <<colour tiddler-editor-border>>;\n}\n\n.tc-lararium-ahu-section {\n  margin: 0.75em 0 0;\n  padding: 0.5em 0 0.5em 0.75em;\n  border-left: 3px solid <<colour primary>>;\n}\n\n.tc-lararium-ahu-section:hover {\n  border-left-color: <<colour primary>>;\n  background: <<colour tiddler-editor-background>>;\n}\n\n/* ── slot header ────────────────────────────────────────────────────────── */\n\n.tc-lararium-ahu-slot-header {\n  display: flex;\n  align-items: center;\n  gap: 0.4em;\n  margin-bottom: 0.3em;\n  font-size: 0.8em;\n  opacity: 0.75;\n}\n\n.tc-lararium-ahu-slot-header:hover {\n  opacity: 1;\n}\n\ncode.tc-ahu-slot-name {\n  font-size: 0.85em;\n  padding: 0.1em 0.4em;\n  border-radius: 3px;\n  background: <<colour code-background>>;\n  color: <<colour code-foreground>>;\n  letter-spacing: 0.02em;\n}\n\n.tc-ahu-edit-btn,\n.tc-ahu-done-btn {\n  padding: 0 0.35em;\n  opacity: 0;\n  transition: opacity 0.15s;\n}\n\n.tc-lararium-ahu-slot-header:hover .tc-ahu-edit-btn {\n  opacity: 1;\n}\n\n/* ── inline edit reveal ─────────────────────────────────────────────────── */\n\n.tc-lararium-ahu-edit-inline {\n  display: flex;\n  flex-direction: column;\n  gap: 0.25em;\n}\n\n.tc-ahu-edit-inline-area {\n  width: 100%;\n  min-height: 6em;\n  font-family: monospace;\n  font-size: 0.9em;\n  resize: vertical;\n}\n\n/* ── breadcrumb ─────────────────────────────────────────────────────────── */\n\n.tc-lararium-ahu-breadcrumb {\n  display: flex;\n  align-items: center;\n  gap: 0.4em;\n  margin-bottom: 0.75em;\n  font-size: 0.8em;\n  opacity: 0.7;\n}\n\n.tc-ahu-label {\n  font-variant: small-caps;\n  letter-spacing: 0.05em;\n}\n\ncode.tc-ahu-slot-badge {\n  padding: 0.1em 0.4em;\n  border-radius: 3px;\n  background: <<colour code-background>>;\n  color: <<colour code-foreground>>;\n}\n\n.tc-ahu-sep {\n  opacity: 0.6;\n}\n\n/* ── edit template ──────────────────────────────────────────────────────── */\n\n.tc-lararium-ahu-edit-sections {\n  margin-top: 1em;\n}\n\n.tc-lararium-ahu-edit-fieldset {\n  border: 1px solid <<colour tiddler-editor-border>>;\n  border-radius: 4px;\n  padding: 0.5em 0.75em;\n}\n\n.tc-lararium-ahu-edit-legend {\n  padding: 0 0.4em;\n  font-size: 0.8em;\n  font-variant: small-caps;\n  letter-spacing: 0.05em;\n  opacity: 0.7;\n}\n\n.tc-lararium-ahu-edit-section {\n  margin: 0.5em 0;\n}\n\n.tc-ahu-edit-body {\n  width: 100%;\n  min-height: 4em;\n  font-family: monospace;\n  font-size: 0.9em;\n  resize: vertical;\n}\n\n/* ── worksite data anchors (invisible structural markers) ───────────────── */\n\nspan[data-lar-kind=\"worksite\"] {\n  display: contents;\n}\n\nspan[data-lar-kind=\"worksite\"]:not([data-lar-slot=\"#body\"]) {\n  display: none;\n}",
